Rule.Source:
  import sailpoint.object.Application;
  import sailpoint.object.Identity;
  import sailpoint.object.Link;
  import sailpoint.object.Filter;
  import sailpoint.object.QueryOptions;
  import sailpoint.tools.Util;
  import sailpoint.api.IdentityService;
  import sailpoint.object.Custom;
  
  String logName = "Ascension-Rule-IdentitySelector-TaskVueSSO";
  
  debug(logName, "Entering rule Ascension-Rule-IdentitySelector-TaskVueSSO");
  
  debug(logName, "RoleName: " + roleName);

  public String getDomain(String principalName) {
    String domainValue = "";

    if (null!=principalName) {

      StringTokenizer stringTokenizer = new StringTokenizer(principalName, "\\");

      if (stringTokenizer.hasMoreTokens()) {
        domainValue = stringTokenizer.nextToken();
      }

    }

    return domainValue;
  }

  private String getPrincipalName(Identity identity) {

    String principalName = "";
    
    List links = identity.getLinks();

    String samAccountName = identity.getAttribute("samAccountName");

    String domain = identity.getAttribute("domain");

    //Check 1 - Proceed when samAccountName is populated;

    if (Util.isEmpty(samAccountName) || links == null) {

      return principalName;

    }

    //Check 2 - Compare the samAccountName attribute of each AD link to the corresponding Identity Attribute; return msDS-PrincipalName if a match is found.

    for (Link link : links) {

      if (link.getApplication().getType().equalsIgnoreCase("Active Directory - Direct")) {

        if(!link.getAttribute("sAMAccountName").equalsIgnoreCase(samAccountName)){

          continue;

        }

        String principalNameAD = link.getAttribute("msDS-PrincipalName");

        if (Util.isNotNullOrEmpty(principalNameAD)) {

          if (domain.equalsIgnoreCase("AMITA")) {

            String appDomainValue = getDomain(principalNameAD);

            if (domain.equalsIgnoreCase(appDomainValue)) {

              principalName = principalNameAD;

            }

            continue;

          }

          principalName = principalNameAD;

        }

      }

    }

    return principalName;

  }

  private boolean checkIfAccountInDSForest(String netBios) {

    boolean isAccountInDSDomain = false;

    if (Util.isNotNullOrEmpty(netBios)) {

      Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-AD-DomainMapping");

      List dsDomainList = custom.get("DS-Domains");

      for (String domainName : dsDomainList) {

        String[] adDomainsStrArray = domainName.split(DOT);

        if (netBios.equalsIgnoreCase(adDomainsStrArray[0])) {

          isAccountInDSDomain = true;

        } 
      }

    }

    return isAccountInDSDomain;
  }

  private void netBiosAdjustment(String netBios) {

    //Adjust Complex Domain NetBIOS to Common Ministry Identifier

    if (Util.nullSafeCaseInsensitiveEq(netBios, "VCHS_NT_DOMAIN")) {

      super.netBios = "VIA-CHRISTI";

    }

  }

  private boolean shouldReceiveTaskVueSSOAccess(String principalName) {
    
    boolean shouldReceiveTaskVueSSOAccess = false;

    //Get everything before the backslash in the msDS-PrincipalName to determine NetBIOS of Domain.

    netBios = principalName.replaceAll("\\\\.*.","");

    if (Util.isNotNullOrEmpty(netBios)) {

      netBiosAdjustment(netBios);

      if (roleName.contains(netBios)) {

        shouldReceiveTaskVueSSOAccess = true;

      } else if (roleName.equalsIgnoreCase("TaskVue_Users-SSO")) {

        shouldReceiveTaskVueSSOAccess = checkIfAccountInDSForest(netBios);

      }

    }

    return shouldReceiveTaskVueSSOAccess;

  }

  static String netBios;

  String    DOT = "\\." ;

  List jobFamilyList = new ArrayList();

  jobFamilyList = Arrays.asList("NUR", "NUS", "ADM");

  if(!identity.isInactive() && jobFamilyList.contains(identity.getStringAttribute("jobFamily"))) {

    String principalName = getPrincipalName(identity);

    if (Util.isNotNullOrEmpty(principalName)) {

      return shouldReceiveTaskVueSSOAccess(principalName);

    }
  }



  return false;
